// 应用启动时，从配置加载插件清单
async function bootstrapPlugins(config: PluginConfig[]) {
  for (const cfg of config) {
    // 动态import——代码分割，按需加载
    const module = await import(/* webpackChunkName: "agent-[request]" */
      `./agents/${cfg.id}/manifest`
    );
    registry.registerAgent(module.default);
  }
